function validateHost(host: string, authToken: string | undefined): string {
  if (authToken !== undefined) { return host; }
  if (!isLoopbackHost(host)) {
    console.error(`${symbol.warn} ${paint.warn(t('cli.serve.warning.host-fallback', { host }))}`);
    return '127.0.0.1';
  }
  return host;
}

export async function loadGetRulesContext(projectRoot: string): Promise<GetRulesContext> {
  const meta = readAgentsMeta(projectRoot);         // sync disk read
  const l0Content = await readFile(join(projectRoot, 'AGENTS.md'), 'utf8');  // async disk read
  const humanLockedNearby = (await readHumanLock(projectRoot)).map(entry => ({ // async disk read
    file: entry.file,
    excerpt: JSON.stringify(entry),
  }));
  return { meta, l0Content, humanLockedNearby };
}

